  g+='<text x="'+padL+'" y="'+(H-7)+'" font-size="9" fill="#71717A">← baisse</text><text x="'+(W-padR)+'" y="'+(H-7)+'" font-size="9" fill="#71717A" text-anchor="end">hausse →</text><text x="11" y="'+(padT+4)+'" font-size="9" fill="#71717A">RVOL ↑</text>';
